const jwt = require('jsonwebtoken');

const JWT_SECRET = 'passEncriptada';
const PUBLIC_ACTIONS = ['getRole'];

const body = $json.body;
const action = body?.action || '';

if (PUBLIC_ACTIONS.includes(action)) {
  return [{ json: { ...$json, _bypass: true } }];
}

const headers = $json.headers || {};
const authHeader = headers['authorization'] || headers['Authorization'] || '';
const bodyToken  = body?.token || '';
const rawToken   = authHeader || bodyToken;

const token = rawToken.replace('Bearer ', '').trim();

if (!token) {
  return [{ json: { _authError: true, status: 401, message: 'Token no proporcionado' } }];
}

try {
  const decoded = jwt.verify(token, JWT_SECRET);
  return [{
    json: {
      ...$json,
      _auth: { id: decoded.id, email: decoded.email, role: decoded.role }
    }
  }];
} catch (err) {
  return [{ json: { _authError: true, status: 401, message: 'Token invÃ¡lido o expirado - ' + err.message } }];
}

const filters = $input.item.json.body.filters || {};
const page = parseInt($input.item.json.body.page) || 1;
const limit = 10;
const offset = (page - 1) * limit;
const conditions = [];
const params = [];
let paramIndex = 1;
let query = `SELECT id, name, surname, email, roleid, enabled, COUNT(*) OVER() as total_count FROM "user" WHERE 1=1`;
if (filters.searchText && typeof filters.searchText === 'string' && filters.searchText.trim() !== '') {
  conditions.push(`(CONCAT(name, ' ', surname) ILIKE $${paramIndex} OR email ILIKE $${paramIndex})`);
  params.push(`%${filters.searchText}%`);
  paramIndex++;
}
if (filters.status !== undefined && filters.status !== null && filters.status !== '') {
  conditions.push(`enabled = $${paramIndex}`);
  params.push(filters.status);
  paramIndex++;
}
if (filters.roleid !== undefined && filters.roleid !== null && filters.roleid !== '') {
  conditions.push(`roleid = $${paramIndex}`);
  params.push(filters.roleid);
  paramIndex++;
}
if (conditions.length > 0) { query += ' AND ' + conditions.join(' AND '); }
query += ` ORDER BY id DESC LIMIT ${limit} OFFSET ${offset}`;
return [{ json: { query, params, page, limit } }];

